@namespace sv_3919dce59cf0402c9a050d5ed7c1f32b.Components.Pages.Apply

<div class="d-flex justify-content-between align-items-center mb-4 step-indicator">
    @for (int i = 0; i < StepNames.Length; i++)
    {
        var step = i + 1;
        var isActive = step == CurrentStep;
