@page "/apply"
@namespace sv_3919dce59cf0402c9a050d5ed7c1f32b.Components.Pages.Apply
@using sv_3919dce59cf0402c9a050d5ed7c1f32b.Models
@using sv_3919dce59cf0402c9a050d5ed7c1f32b.Services
@rendermode InteractiveServer

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4 text-center">Job Application</h2>

    @if (isSubmitted)
    {
        <div class="text-center py-5">
            <div class="mb-3" style="font-size: 3rem; color: green;">&#10003;</div>
            <h3>Application Submitted!</h3>
            <p class="lead">Your application ID is <strong>#@applicationId</strong></p>
            <p class="text-muted">We'll review your application and get back to you soon.</p>
        </div>
    }
    else
    {
        <StepIndicator CurrentStep="currentStep" CompletedSteps="completedSteps" OnStepClicked="GoToStep" />

        @switch (currentStep)
        {
            case 1:
                <PersonalInfoStep Model="personalInfo" OnNext="() => AdvanceStep(2)" />
                break;
            case 2:
                <WorkHistoryStep Entries="workEntries" OnBack="() => GoToStep(1)" OnNext="() => AdvanceStep(3)" />
                break;
            case 3:
                <ReferencesStep References="references" OnBack="() => GoToStep(2)" OnNext="() => AdvanceStep(4)" />
                break;
            case 4:
                <CoverLetterStep @bind-CoverLetter="coverLetter" OnBack="() => GoToStep(3)" OnNext="() => AdvanceStep(5)" />
                break;
            case 5:
                <ReviewStep Personal="personalInfo"
                            WorkEntries="workEntries"
                            References="references"
                            CoverLetter="coverLetter"
                            OnBack="() => GoToStep(4)"
                            OnEditSection="GoToStep"
                            OnSubmit="SubmitApplication" />
                break;
        }
    }
</div>

@code {
    [Inject] private IApplicationService ApplicationService { get; set; } = default!;

    private int currentStep = 1;
    private HashSet<int> completedSteps = new();

    // Form state
    private PersonalInfoModel personalInfo = new();
    private List<WorkEntryModel> workEntries = new() { new WorkEntryModel() };
    private List<ReferenceModel> references = new() { new ReferenceModel(), new ReferenceModel() };
    private string coverLetter = "";

    // Submission state
    private bool isSubmitted;
    private int applicationId;

    private void AdvanceStep(int nextStep)
    {
        completedSteps.Add(currentStep);
        currentStep = nextStep;
    }

    private void GoToStep(int step)
    {
        currentStep = step;
    }

    private async Task SubmitApplication()
    {
        var application = new JobApplication(
            personalInfo.ToRecord(),
            new WorkHistory(workEntries.Select(e => e.ToRecord()).ToList()),
            references.Select(r => r.ToRecord()).ToList(),
            coverLetter
        );

        applicationId = await ApplicationService.SubmitApplicationAsync(application);
        isSubmitted = true;
    }
}

